      <p>{{this.score.runs}}/{{this.score.wickets}}</p>
    {{/if}}
  </template>
}
```
`race()` resolves with the result of the first task or Promise to complete, and cancels all remaining ones automatically. This is ideal for implementing fallback strategies — try multiple sources simultaneously and use whichever is fastest, without leaving unused requests alive.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MatchSummaryComponent extends Component {
  @tracked summary = null

  fetchPlayerOfMatch = task(async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/player-of-match`)
    return response.json()
  })

  fetchScorecard = task(async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/scorecard`)
    return response.json()
  })

  loadMatchSummary = task(async (matchId) => {
    // Perform child tasks sequentially
    const scorecard = await this.fetchScorecard.perform(matchId)
    const playerOfMatch = await this.fetchPlayerOfMatch.perform(matchId)

    this.summary = { scorecard, playerOfMatch }
    return this.summary
  })

  <template>
    <button {{on 'click' (fn this.loadMatchSummary.perform @matchId)}}>Load Summary</button>
    {{#if this.loadMatchSummary.isRunning}}
      <p>Building summary...</p>
    {{/if}}
  </template>
}
```
You can `await` any `.perform()` call inside another task, creating parent-child task relationships. When the parent task is cancelled, all awaited child tasks are also cancelled automatically, propagating cancellation down the chain. This composability is one of ember-concurrency's most powerful features.

```gjs
import Component from '@glimmer/component'
import { task, taskGroup } from 'ember-concurrency'

export default class CricketDataComponent extends Component {
  // Define the group with drop policy
  dataLoaders = taskGroup({ drop: true })

  // Assign tasks to the group
  loadScorecard = task({ group: this.dataLoaders }, async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/scorecard`)
    return response.json()
  })

  loadBowlingFigures = task({ group: this.dataLoaders }, async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/bowling`)
    return response.json()
  })

  <template>
    {{#if this.dataLoaders.isRunning}}
      <p>Loading cricket data...</p>
    {{/if}}
    <button {{on 'click' (fn this.loadScorecard.perform @matchId)}}>Load Scorecard</button>
    <button {{on 'click' (fn this.loadBowlingFigures.perform @matchId)}}>Load Bowling</button>
  </template>
}
```
`taskGroup()` creates a group that applies a concurrency policy across multiple tasks. With `drop: true`, only one task in the entire group runs at a time — if any task in the group is running and another is performed, the new one is dropped. The group's `isRunning` property is `true` if any member task is running.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, taskGroup, timeout } from 'ember-concurrency'

export default class SearchComponent extends Component {
  @tracked results = []

  searchGroup = taskGroup({ restartable: true })

  searchByPlayerName = task({ group: this.searchGroup }, async (query) => {
    await timeout(300)
    const response = await fetch(`/api/players?name=${query}`)
    this.results = await response.json()
  })

  searchByTeam = task({ group: this.searchGroup }, async (query) => {
    await timeout(300)
    const response = await fetch(`/api/teams?q=${query}`)
    this.results = await response.json()
  })

  <template>
    <input
      placeholder="Search players..."
      {{on 'input' (fn this.searchByPlayerName.perform)}}
    />
    <input
      placeholder="Search teams..."
      {{on 'input' (fn this.searchByTeam.perform)}}
    />
    {{#if this.searchGroup.isRunning}}
      <p>Searching...</p>
    {{/if}}
  </template>
}
```
A `restartable` taskGroup cancels the currently running task (from any member) when any member task is newly performed. This ensures that at any point, only the most recently triggered task is running, regardless of which specific task it was. Useful when multiple inputs compete for the same result slot.

```gjs
import Component from '@glimmer/component'
import { task, taskGroup } from 'ember-concurrency'

export default class TournamentComponent extends Component {
  // Step 1: Define the group
  tournamentLoaders = taskGroup({ drop: true })

  // Step 2: Add each task to the group via { group: this.groupName }
  loadFixtures = task({ group: this.tournamentLoaders }, async () => {
    const response = await fetch('/api/tournament/fixtures')
    return response.json()
  })

  loadStandings = task({ group: this.tournamentLoaders }, async () => {
    const response = await fetch('/api/tournament/standings')
    return response.json()
  })

  loadTopScorers = task({ group: this.tournamentLoaders }, async () => {
    const response = await fetch('/api/tournament/top-scorers')
    return response.json()
  })

  <template>
    {{#if this.tournamentLoaders.isRunning}}
      <div class="loading-bar">Loading tournament data...</div>
    {{/if}}
    <button {{on 'click' this.loadFixtures.perform}}>Fixtures</button>
    <button {{on 'click' this.loadStandings.perform}}>Standings</button>
    <button {{on 'click' this.loadTopScorers.perform}}>Top Scorers</button>
  </template>
}
```
Tasks are added to a group by passing `{ group: this.groupName }` as the first argument to `task()`. The group's concurrency policy (`drop`, `restartable`, `enqueue`, `keepLatest`) applies across all member tasks collectively. Each task can still be performed individually; the group only governs how they interact with each other.

```gjs
import Component from '@glimmer/component'
import { task, taskGroup } from 'ember-concurrency'

export default class MatchAnalyticsComponent extends Component {
  analyticsLoaders = taskGroup()

  loadBattingStats = task({ group: this.analyticsLoaders }, async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/batting`)
    return response.json()
