        <span>Loading analytics...</span>
      </div>
    {{/if}}

    <button {{on 'click' (fn this.loadBattingStats.perform @matchId)}}>Batting</button>
    <button {{on 'click' (fn this.loadBowlingStats.perform @matchId)}}>Bowling</button>
    <button {{on 'click' (fn this.loadFieldingStats.perform @matchId)}}>Fielding</button>
  </template>
}
```
`taskGroup.isRunning` is `true` whenever any task in the group is currently executing. This allows you to show a single unified loading state for logically related tasks without tracking each task's `isRunning` individually. It is the primary benefit of using task groups over individual tasks.

```gjs
import Component from '@glimmer/component'
import { task, taskGroup } from 'ember-concurrency'
import { registerDestructor } from '@ember/destroyable'

export default class LiveMatchComponent extends Component {
  constructor(owner, args) {
    super(owner, args)
    registerDestructor(this, () => this.liveDataTasks.cancelAll())
  }

  liveDataTasks = taskGroup()

  pollLiveScore = task({ group: this.liveDataTasks }, async () => {
    while (true) {
      await fetch('/api/live-score')
      await timeout(5000)
    }
  })

  pollCommentary = task({ group: this.liveDataTasks }, async () => {
    while (true) {
      await fetch('/api/live-commentary')
      await timeout(10000)
    }
  })

  stopAll = () => {
    this.liveDataTasks.cancelAll()
  }

  <template>
    <button {{on 'click' this.stopAll}}>Stop All Live Updates</button>
  </template>
}
```
`taskGroup.cancelAll()` cancels all currently running instances of every task belonging to the group in one call. It is more convenient than calling `.cancelAll()` on each task individually. This is especially useful in cleanup scenarios — a single call in `registerDestructor` tears down all related async operations.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class MatchCardComponent extends Component {
  fetchMatch = task(async (matchId) => {
