            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z"></path>
          </svg>
          Loading...
        {{else}}
          Load Match
        {{/if}}
      </button>
    </div>
  </template>
}
```
In GJS templates, `this.taskName.isRunning` is directly accessible and reactive. You can use it inside `{{#if}}` to conditionally render spinners, skeleton loaders, or alternative button labels. The template re-renders automatically as `isRunning` changes — no manual state management required.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { registerDestructor } from '@ember/destroyable'

export default class ScoreTrackerComponent extends Component {
  constructor(owner, args) {
    super(owner, args)
    registerDestructor(this, () => this.trackScore.cancelAll())
  }

  trackScore = task(async () => {
    while (true) {
      await fetch(`/api/matches/${this.args.matchId}/score`)
      await timeout(10000)
    }
  })

  <template>
    {{#if this.trackScore.isIdle}}
