        ▶ Start Tracking
      </button>
    {{else}}
      <div class="flex items-center gap-2 text-green-600">
        <span class="inline-block w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
        Live tracking active
      </div>
      <button {{on 'click' this.trackScore.cancelAll}} class="text-red-500 text-sm">
        Stop
      </button>
    {{/if}}
  </template>
}
```
`task.isIdle` in the template allows you to render different UI states based on whether the task is active or not. This pattern is common for toggle-style features like "start/stop tracking" where you want to alternate between action buttons based on the task's current state.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class FixtureLoaderComponent extends Component {
  loadFixtures = task(async (tournamentId) => {
    const response = await fetch(`/api/tournaments/${tournamentId}/fixtures`)
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`)
    }
    return response.json()
  })

  <template>
    <button
      {{on 'click' (fn this.loadFixtures.perform @tournamentId)}}
      class="px-4 py-2 bg-blue-600 text-white rounded"
    >
      Load Fixtures
    </button>

    {{#if this.loadFixtures.isRunning}}
      <p>Fetching fixtures...</p>
    {{else if this.loadFixtures.last.error}}
      <div class="bg-red-50 border border-red-200 rounded p-3">
        <p class="text-red-700 font-semibold">Failed to load fixtures</p>
        <p class="text-red-500 text-sm">{{this.loadFixtures.last.error.message}}</p>
        <button
          {{on 'click' (fn this.loadFixtures.perform @tournamentId)}}
          class="mt-2 text-blue-600 text-sm underline"
        >
          Try again
        </button>
      </div>
    {{else if this.loadFixtures.last.value}}
      {{#each this.loadFixtures.last.value as |fixture|}}
        <p>{{fixture.homeTeam}} vs {{fixture.awayTeam}}</p>
      {{/each}}
    {{/if}}
  </template>
}
```
`task.last.error` holds the error thrown by the last task execution that failed. Use the three-state pattern in templates: check `isRunning`, then `last.error`, then `last.value`. This gives full control over loading, error, and success UI states without any manual `@tracked` error variable.

```gjs
import Component from '@glimmer/component'
