The `{{perform this.task args...}}` helper is a template-friendly way to create a function that performs the task when invoked. It is equivalent to `(fn this.task.perform args...)` but reads more naturally. Use it with `{{on}}` to wire up task execution directly in the template without writing a wrapper action method.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class ScoreSubmitComponent extends Component {
  submitScore = task({ drop: true }, async (scoreData) => {
    const response = await fetch('/api/scores', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(scoreData)
    })
    return response.json()
  })

  handleSubmit = (event) => {
    const scoreData = {
      runs: parseInt(event.target.runs.value),
      wickets: parseInt(event.target.wickets.value),
      overs: parseFloat(event.target.overs.value)
    }
    this.submitScore.perform(scoreData)
  }

  <template>
    <form {{on 'submit' this.handleSubmit}}>
      <input name="runs" type="number" placeholder="Runs" />
      <input name="wickets" type="number" placeholder="Wickets" />
      <input name="overs" type="number" step="0.1" placeholder="Overs" />

      <button
        type="submit"
        disabled={{this.submitScore.isRunning}}
        class="px-4 py-2 bg-blue-600 text-white rounded disabled:opacity-50 disabled:cursor-not-allowed"
      >
        {{#if this.submitScore.isRunning}}
          Submitting...
        {{else}}
          Submit Score
        {{/if}}
      </button>
    </form>
  </template>
}
```
Binding `disabled={{this.task.isRunning}}` to a button is the standard pattern for preventing duplicate submissions. Combined with the `drop` modifier on the task, this creates a double layer of protection: the button is visually disabled, and even if somehow clicked again, the task drops the new invocation.

```gjs
