import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class ResilientFetcher extends Component {
  @tracked matchData = null
  @tracked retryCount = 0

  fetchWithBackoff = task(async () => {
    const maxRetries = 5
    let delay = 1000 // start with 1 second

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        const response = await fetch(`/api/matches/${this.args.matchId}`)
        if (!response.ok) throw new Error(`HTTP ${response.status}`)
        this.matchData = await response.json()
        this.retryCount = 0
        return
      } catch (err) {
        this.retryCount = attempt
        if (attempt === maxRetries) throw err
        await timeout(delay)
        delay *= 2 // double the delay: 1s, 2s, 4s, 8s, 16s
      }
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchWithBackoff.perform)}}>
      Fetch Match
    </button>
    {{#if this.fetchWithBackoff.isRunning}}
      <p>Attempt {{this.retryCount}}... retrying with backoff</p>
    {{/if}}
    {{#if this.fetchWithBackoff.last.error}}
      <p class="text-red-500">Failed after all retries</p>
    {{/if}}
  </template>
}
```
Exponential backoff prevents hammering a failing server. Starting at 1 second and doubling each time (1s → 2s → 4s → 8s → 16s) gives the server time to recover. The `await timeout(delay)` inside the task is cancellation-aware — if the task is cancelled during a wait, it exits cleanly.

