```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'
import { registerDestructor } from '@ember/destroyable'

export default class LiveBallTracker extends Component {
  @tracked lastBall = null

  pollBallEvents = task(async () => {
    while (true) {
      const response = await fetch(`/api/matches/${this.args.matchId}/last-ball`)
      if (response.ok) {
        this.lastBall = await response.json()
      }
      await timeout(2000)
    }
  })

  constructor(owner, args) {
    super(owner, args)
    registerDestructor(this, () => {
      this.pollBallEvents.cancelAll()
    })
  }

