    <div {{did-insert (fn this.pollBallEvents.perform)}}>
      {{#if this.lastBall}}
        <p>Last ball: {{this.lastBall.result}} by {{this.lastBall.bowler}}</p>
      {{/if}}
    </div>
  </template>
}
