import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, all } from 'ember-concurrency'

export default class MatchWithWeather extends Component {
  @tracked match = null
  @tracked weather = null

  fetchMatch = task(async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}`)
    return res.json()
  })

  fetchWeather = task(async (venueId) => {
    const res = await fetch(`/api/venues/${venueId}/weather`)
    return res.json()
  })

  loadAll = task(async () => {
    const matchId = this.args.matchId
    // First fetch match to get venueId, then fetch both in parallel
    const matchRes = await fetch(`/api/matches/${matchId}`)
    const matchData = await matchRes.json()

    const [fullMatch, weather] = await all([
      this.fetchMatch.perform(matchId),
      this.fetchWeather.perform(matchData.venueId),
    ])
    this.match = fullMatch
    this.weather = weather
  })

  <template>
    <button type="button" {{on "click" (fn this.loadAll.perform)}}>
      Load Match + Weather
    </button>
    {{#if this.match}}
      <p>Match: {{this.match.title}}</p>
      <p>Venue: {{this.match.venue}}</p>
    {{/if}}
    {{#if this.weather}}
      <p>Weather: {{this.weather.condition}}, {{this.weather.tempC}}°C</p>
    {{/if}}
  </template>
}
```
ember-concurrency's `all()` works like `Promise.all()` but is cancellation-aware — if the parent task is cancelled, all child task instances are cancelled too. This ensures you never have orphaned network requests when the component is destroyed mid-flight.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, race, timeout } from 'ember-concurrency'

export default class TimedMatchFetcher extends Component {
  @tracked match = null
  @tracked timedOut = false

  fetchMatchData = task(async () => {
    const res = await fetch(`/api/matches/${this.args.matchId}`)
    return res.json()
  })

  timeoutTask = task(async () => {
    await timeout(5000)
    return '__TIMEOUT__'
  })

  fetchWithTimeout = task(async () => {
    this.timedOut = false
    const result = await race([
      this.fetchMatchData.perform(),
      this.timeoutTask.perform(),
    ])

    if (result === '__TIMEOUT__') {
      this.timedOut = true
      this.fetchMatchData.cancelAll()
    } else {
      this.match = result
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchWithTimeout.perform)}}>
      Fetch (5s timeout)
    </button>
    {{#if this.fetchWithTimeout.isRunning}}
      <p>Loading...</p>
    {{else if this.timedOut}}
      <p class="text-red-500">Request timed out. Try again.</p>
    {{else if this.match}}
      <p>{{this.match.title}}</p>
    {{/if}}
  </template>
}
```
ember-concurrency's `race()` resolves with the first task that completes, similar to `Promise.race()`. Using a sentinel string `'__TIMEOUT__'` distinguishes the timeout from a real API result. After the race, any losing task instances are cancelled automatically, so there are no leaked requests.

