import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class NetRunRateDisplay extends Component {
  computeNRR = task(async (teamId, season) => {
    const [runsForRes, runsAgainstRes] = await Promise.all([
      fetch(`/api/teams/${teamId}/runs-scored?season=${season}`),
      fetch(`/api/teams/${teamId}/runs-conceded?season=${season}`),
