```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class VideoUploader extends Component {
  @tracked uploadProgress = 0
  @tracked uploadedUrl = null

  uploadMatchVideo = task(async (file) => {
    this.uploadProgress = 0

    const uploadedUrl = await new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest()
      const formData = new FormData()
      formData.append('video', file)
      formData.append('matchId', this.args.matchId)

      xhr.upload.addEventListener('progress', (event) => {
        if (event.lengthComputable) {
          this.uploadProgress = Math.round((event.loaded / event.total) * 100)
        }
      })

      xhr.addEventListener('load', () => {
        if (xhr.status >= 200 && xhr.status < 300) {
          resolve(JSON.parse(xhr.responseText).url)
        } else {
          reject(new Error(`Upload failed: ${xhr.status}`))
        }
      })

      xhr.addEventListener('error', () => reject(new Error('Network error')))
      xhr.open('POST', '/api/videos/upload')
      xhr.send(formData)
    })

    this.uploadedUrl = uploadedUrl
  })

  handleFile = (event) => {
    const file = event.target.files[0]
    if (file) this.uploadMatchVideo.perform(file)
  }

  <template>
    <input type="file" accept="video/*" {{on "change" this.handleFile}} />
    {{#if this.uploadMatchVideo.isRunning}}
      <div class="w-full bg-gray-200 rounded">
        <div class="bg-blue-500 h-2 rounded" style="width: {{this.uploadProgress}}%"></div>
      </div>
      <p>{{this.uploadProgress}}% uploaded</p>
    {{/if}}
    {{#if this.uploadedUrl}}
      <p>Done! URL: {{this.uploadedUrl}}</p>
    {{/if}}
  </template>
}
```
`fetch()` does not support upload progress events — use `XMLHttpRequest` wrapped in a `Promise` for real progress tracking. Mutating `@tracked uploadProgress` inside the XHR progress listener triggers Glimmer re-renders, updating the progress bar in real time.

