```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

const writeToIDB = (storeName, data) =>
  new Promise((resolve, reject) => {
    const request = indexedDB.open('spordium', 1)
    request.onupgradeneeded = (e) => {
      e.target.result.createObjectStore(storeName, { keyPath: 'id' })
    }
    request.onsuccess = (e) => {
      const db = e.target.result
      const tx = db.transaction(storeName, 'readwrite')
      tx.objectStore(storeName).put(data)
      tx.oncomplete = () => resolve()
      tx.onerror = () => reject(tx.error)
    }
    request.onerror = () => reject(request.error)
  })

export default class MatchCacheComponent extends Component {
  @tracked saved = false

  saveMatchOffline = task(async (match) => {
    await writeToIDB('matches', match)
    this.saved = true
  })

  <template>
    <button
      type="button"
      disabled={{this.saveMatchOffline.isRunning}}
      {{on "click" (fn this.saveMatchOffline.perform @match)}}
    >
      {{if this.saved 'Saved Offline ✓' 'Save for Offline'}}
    </button>
  </template>
}
```

IndexedDB's callback-based API is wrapped in a plain `Promise` helper (`writeToIDB`) defined outside the component. The task simply `await`s that helper, keeping the task body clean and readable. Errors from either the database open or the transaction propagate through the Promise rejection into the task's error state.

