import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, taskGroup } from 'ember-concurrency'

export default class PipelineComponent extends Component {
  @tracked result = null

  pipeline = taskGroup({ drop: true })

  fetchRaw = task({ group: this.pipeline }, async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/raw`)
    if (!response.ok) throw new Error('Fetch failed')
    return response.json()
  })

  transformData = task({ group: this.pipeline }, async (raw) => {
    return {
      matchId: raw.id,
      totalRuns: raw.innings.reduce((sum, inn) => sum + inn.runs, 0),
      topBatsman: raw.players.sort((a, b) => b.runs - a.runs)[0],
    }
  })

  saveResult = task({ group: this.pipeline }, async (transformed) => {
    const response = await fetch('/api/processed-scores', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(transformed),
    })
    if (!response.ok) throw new Error('Save failed')
    this.result = transformed
  })

  runPipeline = task(async (matchId) => {
    const raw = await this.fetchRaw.perform(matchId)
    const transformed = await this.transformData.perform(raw)
    await this.saveResult.perform(transformed)
  })

  <template>
    <button type="button" {{on "click" (fn this.runPipeline.perform @matchId)}}>
      {{if this.pipeline.isRunning 'Processing...' 'Run Pipeline'}}
    </button>
    {{#if this.result}}
      <p>Saved: {{this.result.totalRuns}} total runs</p>
    {{/if}}
  </template>
}
```

`taskGroup` groups three tasks under a single concurrency constraint. Each stage task declares `{ group: this.pipeline }` to join the group. The `runPipeline` orchestrator task calls each stage in sequence via `perform()`. The template uses `this.pipeline.isRunning` to show a single loading state across all three stages.

