    <button type="button" {{on "click" (fn this.liveFeed.perform @matchId)}}>
      Live Feed
    </button>
    <button type="button" {{on "click" (fn this.archiveFeed.perform @matchId)}}>
      Archive Mode
    </button>
  </template>
}
