import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class PlayerPhotoUploadComponent extends Component {
  @tracked uploadedUrl = null
  @tracked progress = 0

  uploadPhoto = task(async (playerId, file) => {
    const formData = new FormData()
    formData.append('photo', file, file.name)
    formData.append('playerId', playerId)

    // XMLHttpRequest for progress tracking (fetch doesn't support upload progress)
    const url = await new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest()
      xhr.open('POST', `/api/players/${playerId}/photo`)
      xhr.upload.addEventListener('progress', (e) => {
        if (e.lengthComputable) this.progress = Math.round((e.loaded / e.total) * 100)
      })
      xhr.addEventListener('load', () => {
        if (xhr.status >= 200 && xhr.status < 300) {
          resolve(JSON.parse(xhr.responseText).url)
        } else {
          reject(new Error(`Upload failed: ${xhr.status}`))
        }
      })
      xhr.addEventListener('error', () => reject(new Error('Network error')))
      xhr.send(formData)
    })

    this.uploadedUrl = url
    this.progress = 0
    return url
  })

  <template>
    <input type="file" accept="image/*"
      {{on "change" (fn (action (mut this._file)) value="target.files.0")}}
    />
    <button type="button" {{on "click" (fn this.uploadPhoto.perform @playerId this._file)}}>
      Upload Photo
    </button>
    {{#if this.uploadPhoto.isRunning}}
      <progress value={{this.progress}} max="100">{{this.progress}}%</progress>
    {{/if}}
  </template>
}
```

`FormData` automatically sets the correct `multipart/form-data` Content-Type with boundary. Since `fetch` doesn't expose upload progress events, `XMLHttpRequest` is wrapped in a `Promise` to allow `await`. The `progress` event listener updates `@tracked progress` reactively during upload. The task cleans up `progress` to 0 after completion.

