import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'
import { action } from '@ember/object'

export default class MatchNotesComponent extends Component {
  @tracked notes = ''
  @tracked lastSaved = null

  saveDraft = task({ restartable: true }, async (matchId, content) => {
    await timeout(1000) // Wait 1 second after last keystroke
    const response = await fetch(`/api/matches/${matchId}/draft`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ notes: content }),
    })
    if (!response.ok) throw new Error('Draft save failed')
    this.lastSaved = new Date().toLocaleTimeString()
  })

  @action
  onInput(matchId, event) {
    this.notes = event.target.value
    this.saveDraft.perform(matchId, this.notes)
  }

  <template>
    <textarea
      value={{this.notes}}
      {{on "input" (fn this.onInput @matchId)}}
      placeholder="Match notes..."
    ></textarea>
    {{#if this.saveDraft.isRunning}}
      <span class="text-gray-400">Saving...</span>
    {{else if this.lastSaved}}
      <span class="text-green-500">Saved at {{this.lastSaved}}</span>
    {{/if}}
  </template>
}
```

`{ restartable: true }` is the key to debouncing with ember-concurrency. Each keystroke calls `this.saveDraft.perform()`, which cancels the previous running instance and restarts the 1-second `timeout()`. The API call only fires after the user stops typing for 1 second. This eliminates the need for a separate debounce utility function.

