import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MatchProcessorComponent extends Component {
  @tracked step = null
  @tracked result = null

  processMatch = task(async (matchId) => {
    // Step 1: Fetch
    this.step = 'Fetching match data...'
    const fetchRes = await fetch(`/api/matches/${matchId}/raw`)
    if (!fetchRes.ok) throw new Error('Fetch failed')
    const rawData = await fetchRes.json()

    // Step 2: Transform
    this.step = 'Processing innings...'
    const transformed = {
      matchId: rawData.id,
      summary: `${rawData.homeTeam} vs ${rawData.awayTeam}`,
      netRunRate: (
        rawData.innings[0].runs / rawData.innings[0].overs -
        rawData.innings[1].runs / rawData.innings[1].overs
      ).toFixed(3),
      winner: rawData.result.winner,
    }

    // Step 3: Save
    this.step = 'Saving processed data...'
    const saveRes = await fetch('/api/processed-matches', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(transformed),
    })
    if (!saveRes.ok) throw new Error('Save failed')
    this.result = transformed
    this.step = 'Complete'
    return transformed
  })

  <template>
    <button type="button" {{on "click" (fn this.processMatch.perform @matchId)}}>
      Process Match
    </button>
    {{#if this.step}}
      <p class="text-sm">{{this.step}}</p>
    {{/if}}
  </template>
}
```

Chaining three `await` calls in sequence inside a single task is the simplest and most readable pattern for serial async workflows. Updating `@tracked step` before each stage gives users real-time progress feedback. If any step throws, the task fails at that stage and the error is available via `last.error` — subsequent steps are never executed.

