```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, all } from 'ember-concurrency'

export default class SequentialParallelComponent extends Component {
  @tracked firstGroupData = []
  @tracked secondGroupData = []

  loadAllData = task(async (matchId) => {
    // First group: team and venue data (run in parallel)
    const [teamData, venueData] = await all([
      fetch(`/api/matches/${matchId}/teams`).then((r) => r.json()),
      fetch(`/api/matches/${matchId}/venue`).then((r) => r.json()),
    ])
    this.firstGroupData = [teamData, venueData]

    // Second group (starts only after first group completes): innings and stats
    const [inningsData, statsData] = await all([
      fetch(`/api/matches/${matchId}/innings`).then((r) => r.json()),
      fetch(`/api/matches/${matchId}/stats`).then((r) => r.json()),
    ])
    this.secondGroupData = [inningsData, statsData]

    return { teamData, venueData, inningsData, statsData }
  })

  <template>
    <button type="button" {{on "click" (fn this.loadAllData.perform @matchId)}}>
      {{if this.loadAllData.isRunning 'Loading...' 'Load All Data'}}
    </button>
  </template>
}
```

`all()` from ember-concurrency is a cancellation-aware equivalent of `Promise.all()` — if the enclosing task is cancelled, all inner tasks/promises are also cancelled. Using two sequential `await all([...])` calls achieves the pattern: group one's items run concurrently, and group two's items only start after group one finishes. This is ideal when the second group depends on data from the first.

