  })

  <template>
    {{#if this.fetchScore.isRunning}}
      <p>Loading score...</p>
    {{else if this.fetchScore.last.value}}
      <p>Score: {{this.fetchScore.last.value.runs}}</p>
    {{/if}}
    <button {{on "click" (perform this.fetchScore)}}>Refresh</button>
  </template>
}
```

`task()` wraps an async function and gives it a managed lifecycle. Unlike plain `async/await`, a task automatically cancels when its owning component is destroyed, preventing state updates on unmounted components. It also exposes reactive state like `isRunning`, `last.value`, and `last.error` directly in templates without any extra `@tracked` boilerplate. Think of `task()` as `async/await` with superpowers: cancellation, concurrency control, and built-in loading state.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'

export default class LiveScoreBoard extends Component {
  pollScore = task(async () => {
    while (true) {
      const res = await fetch('/api/live-score')
      const data = await res.json()
      console.log('Score updated:', data.runs)
      await timeout(5000) // cancellation point — task pauses here
    }
  })

  cancelPolling = () => {
    this.pollScore.cancelAll() // signals cancellation at next await point
  }

  <template>
    <button {{on "click" (perform this.pollScore)}}>Start Polling</button>
    <button {{on "click" this.cancelPolling}}>Stop</button>
    {{#if this.pollScore.isRunning}}
      <span>🔴 Live</span>
    {{/if}}
  </template>
}
```

ember-concurrency uses generator-based coroutines internally. Every `await` inside a task is a "cancellation point" — when cancellation is requested, the task simply stops at the next `await` and does not resume. This is why `timeout()` (from ember-concurrency) is cancellation-safe but `setTimeout` wrapped in a Promise is not: a raw `setTimeout` callback fires regardless of cancellation. Cancellation is cooperative — the task must reach an `await` before it stops. The `finally` block always runs, giving you a chance to clean up.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'

export default class PlayerStatsLoader extends Component {
  loadStats = task(async () => {
    await timeout(3000) // simulates slow network
    const res = await fetch(`/api/players/${this.args.playerId}/stats`)
    // ✅ If component is destroyed before this line, task is already cancelled
    // No 'cannot set property on destroyed object' error
    return await res.json()
  })

  <template>
    {{#if this.loadStats.isRunning}}
      <p>Loading player stats...</p>
    {{else}}
      <p>{{this.loadStats.last.value.battingAverage}}</p>
    {{/if}}
  </template>
}
```

ember-concurrency registers each task with Ember's owner/container system using the `@ember/destroyable` API. When a component is torn down (e.g., route change, `{{if}}` toggle), Ember fires destruction hooks, which ember-concurrency listens to. It then calls `cancelAll()` on every task that belongs to that component. This means you never need to manually cancel tasks in a `willDestroy` hook for component-owned tasks. This solves the classic React bug of "setState on unmounted component" entirely automatically.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class ScoreRefreshButton extends Component {
  // With drop: if task is already running, new perform() calls are silently ignored
  refreshScore = task({ drop: true }, async () => {
    const res = await fetch(`/api/matches/${this.args.matchId}/score`)
    const data = await res.json()
    return data
  })

  <template>
    {{! Clicking rapidly only triggers ONE fetch — extras are dropped }}
    <button
      {{on "click" (perform this.refreshScore)}}
      disabled={{this.refreshScore.isRunning}}
    >
      {{#if this.refreshScore.isRunning}}Refreshing...{{else}}Refresh Score{{/if}}
    </button>
  </template>
}
```

The `drop` modifier means: "if an instance of this task is already running, throw away (drop) any new `perform()` calls until the current run finishes." It protects against duplicate network requests from impatient button clicks. Unlike `restartable` (which cancels the old run), `drop` lets the in-progress run complete and ignores latecomers. Use `drop` when the operation is idempotent and you want exactly one execution at a time — like a score refresh button or a save action.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'

export default class PlayerSearchBox extends Component {
  @tracked query = ''

  // restartable: each new perform() cancels the previous run and starts over
  searchPlayers = task({ restartable: true }, async (query) => {
    await timeout(300) // debounce: cancelled if user types again within 300ms
    const res = await fetch(`/api/players?q=${encodeURIComponent(query)}`)
    return await res.json()
  })

  handleInput = (e) => {
    this.query = e.target.value
    this.searchPlayers.perform(this.query)
  }

  <template>
    <input value={{this.query}} {{on "input" this.handleInput}} />
    {{#each this.searchPlayers.last.value as |player|}}
      <p>{{player.name}}</p>
    {{/each}}
  </template>
}
```

With `restartable`, every new `perform()` immediately cancels the currently running instance and starts a fresh one. This is the natural choice for search/typeahead: you always want the result for the *latest* input, not a stale earlier one. Combined with `timeout()` for debouncing, it creates a clean typeahead with zero memory leaks. The old fetch is cancelled at the `await timeout` point before it even hits the network.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class AutoSaveInnings extends Component {
  // keepLatest: runs current, remembers ONLY the last queued call, drops the rest
  saveInnings = task({ keepLatest: true }, async (inningsData) => {
    await fetch('/api/innings', {
      method: 'POST',
      body: JSON.stringify(inningsData)
    })
  })

  handleChange = (field, value) => {
    const updated = { ...this.args.innings, [field]: value }
    this.saveInnings.perform(updated) // rapid calls: only latest queued
  }

  <template>
    {{#if this.saveInnings.isRunning}}
      <span>Saving...</span>
    {{/if}}
    <input {{on "input" (fn this.handleChange "runs")}} />
  </template>
}
```

`keepLatest` sits between `drop` and `enqueue`. It lets the current run finish (like `drop`), but also remembers the single most recent pending call and executes it after the current run completes. If you call `perform()` five times while running, only the 5th call is kept — the 2nd, 3rd, and 4th are dropped. This is perfect for auto-save: you want to save the very latest state, not queue every keystroke, and you don't want to cancel a save that's in progress.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class BallEventLogger extends Component {
  // enqueue: all perform() calls run ONE AT A TIME in order — no drops
  logBallEvent = task({ enqueue: true }, async (ballEvent) => {
    const res = await fetch('/api/ball-events', {
      method: 'POST',
      body: JSON.stringify(ballEvent)
    })
    return await res.json()
  })

  recordBoundary = () => this.logBallEvent.perform({ type: 'boundary', runs: 4 })
  recordWicket = () => this.logBallEvent.perform({ type: 'wicket', runs: 0 })
  recordSix = () => this.logBallEvent.perform({ type: 'six', runs: 6 })

  <template>
    <p>Queue length: {{this.logBallEvent.numQueued}}</p>
    <button {{on "click" this.recordBoundary}}>Boundary (4)</button>
    <button {{on "click" this.recordWicket}}>Wicket</button>
    <button {{on "click" this.recordSix}}>Six (6)</button>
  </template>
}
```

`enqueue` guarantees that all `perform()` calls are executed sequentially — no call is dropped or cancelled. New calls wait in a queue until the current one finishes. This is critical when order matters, like logging ball-by-ball events to a server. The task exposes `numQueued` to show how many calls are waiting. Use `enqueue` when you need guaranteed delivery of every call in the exact order they were made.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class TournamentFixtures extends Component {
  // maxConcurrency: at most 3 fetches run simultaneously, rest are enqueued
  fetchFixture = task({ enqueue: true, maxConcurrency: 3 }, async (fixtureId) => {
    const res = await fetch(`/api/fixtures/${fixtureId}`)
    return await res.json()
  })

  loadAll = async () => {
    const ids = this.args.fixtureIds // e.g., 20 fixture IDs
    ids.forEach(id => this.fetchFixture.perform(id))
  }

  <template>
    <button {{on "click" this.loadAll}}>Load All Fixtures</button>
    <p>Running: {{this.fetchFixture.numRunning}} / Queued: {{this.fetchFixture.numQueued}}</p>
  </template>
}
```

`maxConcurrency` caps how many instances of a task run at the same time. It's typically combined with `enqueue` (queue extras) but can also combine with `drop` (drop extras beyond the cap). With `maxConcurrency: 3`, three fetches run in parallel; as each finishes, the next queued one starts. This is a controlled parallel fetch — useful when loading many fixtures/players simultaneously without overwhelming the server. `numRunning` and `numQueued` are reactive and accessible in templates.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class MatchLoader extends Component {
  // 'loadMatch' is the TASK — a blueprint/descriptor
  loadMatch = task(async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}`)
    return await res.json()
  })

  runExample = async () => {
    // 'instance' is a TASK INSTANCE — one specific execution
    const instance = this.loadMatch.perform('match-123')

    console.log(instance.isRunning)   // true
    console.log(instance.value)       // null (still running)

    const result = await instance     // await the instance like a Promise
    console.log(result.teams)         // { home: 'India', away: 'Australia' }

    // The task itself aggregates all instances
    console.log(this.loadMatch.last === instance) // true
  }

  <template>
    <button {{on "click" (perform this.loadMatch "match-456")}}>Load Match</button>
    {{! task.last refers to the most recent TaskInstance }}
    <p>{{this.loadMatch.last.value.venue}}</p>
  </template>
}
```

The **task** (`loadMatch`) is a persistent object that lives on the component — it holds aggregate state like `isRunning`, `last`, and `performCount`. A **TaskInstance** is a single execution created each time `.perform()` is called — it has its own `isRunning`, `value`, `error`, and `isCancelled`. You can `await` a TaskInstance like a Promise. `task.last` always points to the most recently created instance, while `task.lastSuccessful` points to the last one that completed without error or cancellation.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class ScoreHistory extends Component {
  fetchScore = task(async (matchId) => {
    if (!matchId) throw new Error('No match ID')
    const res = await fetch(`/api/matches/${matchId}/score`)
    if (!res.ok) throw new Error('Fetch failed')
    return await res.json()
  })

  <template>
    {{! task.last — most recent instance, ANY outcome (running/error/cancelled/ok) }}
    <p>Last attempt status: {{this.fetchScore.last.state}}</p>

    {{! task.lastSuccessful — last instance that returned a value without error }}
    {{#if this.fetchScore.lastSuccessful}}
      <p>Last good score: {{this.fetchScore.lastSuccessful.value.runs}}</p>
    {{/if}}

    {{! task.lastComplete — last instance that finished (success OR error, not cancelled) }}
    {{#if this.fetchScore.lastComplete.error}}
      <p class="text-red-600">Error: {{this.fetchScore.lastComplete.error.message}}</p>
    {{/if}}
  </template>
}
```

`task.last` is the most recently *started* instance regardless of outcome — useful for showing the current state. `task.lastSuccessful` only references instances that completed with a return value and no error — safe to use for displaying data. `task.lastComplete` is the most recent instance that *finished* (either success or error) but was not cancelled — useful for showing error messages without clearing them when a new attempt is running. These three give you fine-grained UI control.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class LiveOverCounter extends Component {
  // No @tracked needed — task state is already reactive
  countOvers = task(async () => {
    let over = 0
    while (over < 50) {
      await fetch(`/api/match/over/${over}`)
      over++
    }
    return over
  })

  <template>
    {{! isRunning, last.value are tracked internally by ember-concurrency }}
    {{#if this.countOvers.isRunning}}
      <div class="animate-pulse">Counting overs...</div>
    {{else}}
      <div>Done: {{this.countOvers.last.value}} overs</div>
    {{/if}}
    <button {{on "click" (perform this.countOvers)}}>Start</button>
  </template>
}
```

ember-concurrency uses Glimmer's `@tracked` storage internally for all task state properties (`isRunning`, `isIdle`, `last`, `numRunning`, etc.). When you install ember-concurrency v3+, it hooks into `@glimmer/tracking` primitives so that any template that reads `task.isRunning` automatically re-renders when that value changes. You don't need to manually declare `@tracked isLoading = false` and toggle it — the task is its own reactive state machine. This eliminates an entire class of bugs where developers forget to reset loading flags.

```gjs
import Component from '@glimmer/component'
import { task, taskGroup } from 'ember-concurrency'

export default class MatchDataLoader extends Component {
  // taskGroup acts as a shared concurrency policy for multiple tasks
  dataLoading = taskGroup({ drop: true })

  fetchScore = task({ group: this.dataLoading }, async () => {
    const res = await fetch('/api/score')
    return await res.json()
  })

  fetchLineup = task({ group: this.dataLoading }, async () => {
    const res = await fetch('/api/lineup')
    return await res.json()
  })

  fetchWeather = task({ group: this.dataLoading }, async () => {
    const res = await fetch('/api/weather')
    return await res.json()
  })

  <template>
    {{! isRunning is true if ANY grouped task is running }}
    {{#if this.dataLoading.isRunning}}
      <p>Loading match data...</p>
    {{/if}}
    <button {{on "click" (perform this.fetchScore)}}>Score</button>
    <button {{on "click" (perform this.fetchLineup)}}>Lineup</button>
  </template>
}
```

A `taskGroup` applies a single concurrency policy (like `drop`) across multiple distinct tasks. If any task in the group is running, the group's `isRunning` is `true` — giving you a single loading indicator for multiple operations. The `drop` policy on the group means only one task across the entire group runs at a time. This is useful for "load panel data" scenarios where clicking any load button while one is in progress should be ignored.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'

export default class PollLiveScore extends Component {
  // ❌ Using raw Promise setTimeout — NOT cancellation-safe
  pollWithRawTimeout = task(async () => {
    while (true) {
      await new Promise(resolve => setTimeout(resolve, 3000))
      // Even if task is cancelled, setTimeout fires and code continues
      await fetch('/api/live-score') // runs even after component destroyed!
    }
  })

  // ✅ Using ember-concurrency timeout() — cancellation-safe
  pollWithTimeout = task(async () => {
    while (true) {
      await timeout(3000) // this is a cancellation point
      // If task cancelled during timeout, execution STOPS HERE
      const res = await fetch('/api/live-score')
      const data = await res.json()
      console.log('Score:', data.runs)
    }
  })

  <template>
    <button {{on "click" (perform this.pollWithTimeout)}}>Poll</button>
    <button {{on "click" (fn this.pollWithTimeout.cancelAll)}}>Stop</button>
  </template>
}
```

`timeout()` from ember-concurrency is a special awaitable that integrates with the task's cancellation mechanism. When the task is cancelled, any pending `timeout()` is immediately resolved and cancellation propagates — the code after `await timeout()` never runs. A raw `setTimeout` wrapped in a Promise schedules a macrotask outside ember-concurrency's control; even if the task is cancelled, the callback fires, leading to potential updates on destroyed components. Always use `timeout()` for delays inside tasks.

```gjs
import Component from '@glimmer/component'
import { task, waitForEvent } from 'ember-concurrency'

export default class ScoreboardWebSocket extends Component {
  listenForUpdates = task(async () => {
    const ws = new WebSocket('wss://api.spordium.com/live')

    // ✅ waitForEvent — cancellation-safe, auto-cleans up listener
    const openEvent = await waitForEvent(ws, 'open')
    console.log('WebSocket connected')

    while (true) {
      const messageEvent = await waitForEvent(ws, 'message')
      const data = JSON.parse(messageEvent.data)
      console.log('Score update:', data.runs)
      // If task cancelled here, listener is automatically removed
    }
  })

  <template>
    <button {{on "click" (perform this.listenForUpdates)}}>Connect</button>
    <button {{on "click" (fn this.listenForUpdates.cancelAll)}}>Disconnect</button>
  </template>
}
```

`waitForEvent(target, eventName)` adds an event listener, waits for the event, then *automatically removes the listener* — whether the event fires or the task is cancelled. A raw `addEventListener` wrapped in a `new Promise()` has no cleanup mechanism: if the task is cancelled before the event fires, the listener leaks permanently. `waitForEvent` ensures that cancellation = cleanup, preventing event listener accumulation across multiple task runs.

```gjs
import Component from '@glimmer/component'
import { task, waitForProperty } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class MatchReadinessChecker extends Component {
  @tracked isMatchReady = false
  @tracked connectionStatus = 'disconnected'

  waitForReady = task(async () => {
    // ✅ waitForProperty — suspends until condition is true, no CPU spin
    await waitForProperty(this, 'isMatchReady', val => val === true)
    console.log('Match is ready!')

    await waitForProperty(this, 'connectionStatus', 'connected')
    console.log('Connected — starting live updates')
  })

  simulateReady = () => { this.isMatchReady = true }
  simulateConnect = () => { this.connectionStatus = 'connected' }

  <template>
    <button {{on "click" (perform this.waitForReady)}}>Wait for Ready</button>
    <button {{on "click" this.simulateReady}}>Set Ready</button>
    <button {{on "click" this.simulateConnect}}>Connect</button>
  </template>
}
```

`waitForProperty(obj, key, predicateOrValue)` suspends the task until a `@tracked` property satisfies a condition, using Glimmer's reactive system rather than polling. It's cancellation-safe: if the task is cancelled while waiting, the watcher is removed. A `while (!this.isMatchReady) { await timeout(100) }` loop wastes CPU checking every 100ms. `waitForProperty` is event-driven — it only resumes when the tracked property actually changes, making it both more efficient and more responsive.

```gjs
import Component from '@glimmer/component'
import { task, all } from 'ember-concurrency'

export default class MatchDayLoader extends Component {
  loadMatchDay = task(async (matchId) => {
    // ✅ ember-concurrency all() — if THIS task is cancelled, all sub-tasks cancel too
    const [score, lineup, weather] = await all([
      fetch(`/api/matches/${matchId}/score`).then(r => r.json()),
      fetch(`/api/matches/${matchId}/lineup`).then(r => r.json()),
      fetch(`/api/weather?venue=${matchId}`).then(r => r.json())
    ])

    return { score, lineup, weather }
  })

  // ❌ Using Promise.all() — if task cancelled, fetches continue running!
  loadMatchDayBad = task(async (matchId) => {
    const [score, lineup] = await Promise.all([
      fetch(`/api/matches/${matchId}/score`).then(r => r.json()),
      fetch(`/api/matches/${matchId}/lineup`).then(r => r.json())
    ])
    return { score, lineup }
  })

  <template>
    <button {{on "click" (perform this.loadMatchDay this.args.matchId)}}>Load</button>
    <p>{{this.loadMatchDay.last.value.score.runs}}</p>
  </template>
}
```

`all()` from ember-concurrency behaves like `Promise.all()` but is cancellation-aware. If the containing task is cancelled while `await all([...])` is pending, the remaining promises are abandoned and do not update component state. `Promise.all()` continues running all its promises regardless of task cancellation — they complete in the background with no way to stop them. Prefer `all()` whenever running parallel operations inside a task that might be cancelled or restarted.

```gjs
import Component from '@glimmer/component'
import { task, race, timeout } from 'ember-concurrency'

export default class ScoreWithTimeout extends Component {
  fetchWithTimeout = task(async (matchId) => {
    // ✅ race() — loser is automatically cleaned up on cancellation
    const result = await race([
      fetch(`/api/matches/${matchId}/score`).then(r => r.json()),
      timeout(5000).then(() => ({ error: 'timeout' }))
    ])

    if (result.error === 'timeout') {
      return { runs: 0, status: 'timeout' }
    }
    return result
  })

  <template>
    <button {{on "click" (perform this.fetchWithTimeout this.args.matchId)}}>Fetch</button>
    {{#if (eq this.fetchWithTimeout.last.value.status "timeout")}}
      <p class="text-yellow-600">Request timed out</p>
    {{else}}
      <p>{{this.fetchWithTimeout.last.value.runs}} runs</p>
    {{/if}}
  </template>
}
```

`race()` resolves with the first promise to complete, just like `Promise.race()`. The key difference is cleanup: if the containing task is cancelled while waiting, `race()` stops tracking all competing promises — they don't fire any callbacks. `Promise.race()` callbacks continue executing after the race resolves, which can cause side effects in a cancelled task. `race()` is also the idiomatic way to implement fetch timeouts inside ember-concurrency tasks.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'

export default class OverByOverAnalysis extends Component {
