}
```

ember-concurrency stores all task state (`isRunning`, `performCount`, `last`, etc.) using `@glimmer/tracking` cells internally. This means templates that read task properties automatically subscribe to changes and re-render without any manual `notifyPropertyChange` calls. When a task starts or finishes, affected templates update automatically — the same way `@tracked` properties trigger re-renders. This makes ember-concurrency a first-class citizen in the Glimmer reactivity model.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class BatsmanCard extends Component {
  // No @tracked needed for loading state — task provides it for free
  loadBatsman = task(async (playerId) => {
    const res = await fetch(`/api/players/${playerId}/batting-stats`)
    return await res.json()
  })

