```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class ScorecardComponent extends Component {
  @tracked runs = this.args.initialRuns

  addRuns = task({ drop: true }, async (runsToAdd) => {
    const previousRuns = this.runs
    // Optimistically update UI immediately
    this.runs += runsToAdd

    try {
      await fetch('/api/score/add', {
        method: 'POST',
        body: JSON.stringify({ runs: runsToAdd }),
      })
    } catch (e) {
      // Rollback on failure
      this.runs = previousRuns
      throw e
    }
  })

  <template>
    <p>Score: {{this.runs}}</p>
    <button {{on "click" (fn (perform this.addRuns) 4)}}>+4</button>
  </template>
}
```
