```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

// ❌ drop — loses submissions that arrive while one is in-flight
// submitScore = task({ drop: true }, async (scoreData) => { ... })

// ✅ enqueue — serializes all submissions, none are lost
export default class BulkScoreSubmitComponent extends Component {
  submitScore = task({ enqueue: true }, async (scoreData) => {
