```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'

// ❌ Manual retry — verbose, state leaks, no integration with task loading state
// @tracked retryCount = 0
// @action async loadWithRetry() {
//   while (this.retryCount < 3) {
//     try { return await fetch(...); break } catch { this.retryCount++ }
//   }
// }

// ✅ task with retry loop — clean, loading state built in
export default class RetryFetchComponent extends Component {
  fetchMatchWithRetry = task(async (matchId) => {
    const maxRetries = 3
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        const res = await fetch(`/api/matches/${matchId}`)
        if (!res.ok) throw new Error(`HTTP ${res.status}`)
        return await res.json()
      } catch (e) {
        if (attempt === maxRetries) throw e
        await timeout(attempt * 1000) // exponential backoff
      }
    }
  })
}
```
Implement retry logic inside the task itself using a `for` loop with exponential backoff via `timeout()`. This keeps all retry state local to the task function — no `@tracked retryCount` needed. `task.isRunning` correctly shows `true` across all retry attempts. The task's `last.error` is only set after all retries are exhausted. Manual retry counters in `@tracked` are error-prone and don't reset cleanly between different task invocations.

