import { task, waitForEvent } from 'ember-concurrency'

export default class VideoUploadComponent extends Component {
  @tracked uploadProgress = 0

  // ✅ task wrapping XHR — get progress AND task state management
  uploadVideo = task({ drop: true }, async (file) => {
    const xhr = new XMLHttpRequest()
    const formData = new FormData()
    formData.append('video', file)

    xhr.open('POST', '/api/videos/upload')

    xhr.upload.addEventListener('progress', (e) => {
      if (e.lengthComputable) {
        this.uploadProgress = Math.round((e.loaded / e.total) * 100)
      }
    })

    xhr.send(formData)
    await waitForEvent(xhr, 'load')
    return JSON.parse(xhr.responseText)
  })

  <template>
    <p>{{this.uploadProgress}}%</p>
    <button {{on "click" (fn (perform this.uploadVideo) @file)}}>Upload</button>
  </template>
}
```
