// ✅ RECOMMENDED: retry inside the task for transient errors
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class LiveScoreComponent extends Component {
  @tracked score = null

  fetchScore = task(async () => {
    let attempts = 0
    while (attempts < 3) {
      try {
        this.score = await fetch(`/api/match/${this.args.matchId}/score`).then(r => r.json())
        return
      } catch (e) {
        attempts += 1
        if (attempts >= 3) throw e
        await timeout(1000 * attempts) // exponential backoff
      }
    }
  })

  <template>
    {{#if this.fetchScore.last.error}}
      <p class="text-red-500">Score unavailable. <button {{on "click" (perform this.fetchScore)}}>Retry</button></p>
    {{else}}
      <p>{{this.score.runs}}/{{this.score.wickets}}</p>
    {{/if}}
  </template>
}
```

Retry inside the task for transient, component-specific errors (network blip, 503 during peak match time) — the task knows the context (which match, how many attempts) and can implement exponential backoff cleanly. A global error handler is the right place for authentication errors (401 → redirect to login), truly unexpected errors (500 bugs), or cross-cutting concerns like error reporting to Sentry. These two mechanisms are complementary: task-level retry handles recoverable errors gracefully before the global handler ever sees them.

