import { inject as service } from '@ember/service'

export default class AuthenticatedRoute extends Route {
  @service auth

  async beforeModel(transition) {
    await this.auth.checkSession.perform() // runs on every route transition
    if (!this.auth.isAuthenticated) {
      transition.abort()
      this.router.transitionTo('login')
    }
  }
}

// In AuthService — periodic check for idle users
import Service from '@ember/service'
import { task, timeout } from 'ember-concurrency'

export default class AuthService extends Service {
  pollSession = task(async () => {
    while (true) {
      await timeout(5 * 60 * 1000) // every 5 minutes
      await this.checkSession.perform()
    }
  })

  checkSession = task({ drop: true }, async () => {
    const res = await fetch('/api/auth/session').then(r => r.json())
    this.isAuthenticated = res.valid
  })
}
```

`beforeModel` is mandatory for transition-time checks — it gates route access and is the canonical Ember pattern for auth guards. But users who stay on the same page (e.g., watching live match commentary) never trigger transitions, so their session can expire silently. A periodic polling task handles this idle case. Use both together: `beforeModel` for hard gates on navigation, a background polling task for idle session expiry with graceful logout prompts.

