// ✅ RECOMMENDED: CSS @font-face for standard fonts — zero JS overhead
// In app.css:
// @font-face {
//   font-family: 'ScoreboardMono';
//   src: url('/fonts/scoreboard-mono.woff2') format('woff2');
//   font-display: swap;
// }

// ✅ task (use only when font load timing must be controlled programmatically)
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class LiveScoreboardComponent extends Component {
  @tracked fontReady = false

  loadScoreFont = task(async () => {
    const font = new FontFace('ScoreboardMono', 'url(/fonts/scoreboard-mono.woff2)')
    await font.load()
    document.fonts.add(font)
    this.fontReady = true
  })

  <template>
    {{#if this.fontReady}}
      <div style="font-family: ScoreboardMono">{{@score}}</div>
    {{else}}
      <div>{{@score}}</div>
    {{/if}}
  </template>
}
```

CSS `@font-face` with `font-display: swap` is always the default choice — the browser handles loading asynchronously, shows a fallback font immediately, then swaps without any JavaScript. Use the FontFace API in a task only when you need to know the exact moment the font is ready (e.g., to prevent a flash of wrong layout in a scoreboard animation, or to load fonts conditionally based on user settings). The task approach adds meaningful complexity; use it only when CSS font loading gives insufficient timing control.

